{"tool":"sql_query","args":{"query":"WITH c AS (
  SELECT * FROM 'tables/chassis_brake_validation_specs.csv'
), v AS (
  SELECT * FROM 'tables/vehicle_variant_configuration_specs.csv'
), joined AS (
  SELECT c.test_id, c.vehicle_variant, c.axle_config, CAST(c.stability_margin_pct AS REAL) AS stability_margin_pct,
         v.variant_id, v.trim_level
  FROM c
  JOIN v ON c.vehicle_variant = v.variant_id
  WHERE lower(c.axle_config) = 'air-multilink'
    AND lower(v.trim_level) IN ('executive','premium')
), ranked AS (
  SELECT *, ROW_NUMBER() OVER (ORDER BY stability_margin_pct DESC, test_id, vehicle_variant) AS rn,
         COUNT(*) OVER () AS row_count
  FROM joined
)
SELECT row_count, test_id, vehicle_variant, variant_id, trim_level, axle_config, stability_margin_pct
FROM ranked
WHERE rn = 1;"}}
{"answer":"4 rows. Highest stability_margin_pct among air-multilink with Executive/Premium is test_id CT-204, vehicle_variant VX-ELX-900 / variant_id VX-ELX-900, trim_level Executive, axle_config air-multilink, stability_margin_pct 18.9."}

